// Vector Addition in CUDA
#include <stdio.h>

// CUDA Kernel for Vector Addition
__global__ void vectorAdd(float *a, float *b, float *c, int n) {
    // Calculate global thread index
    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    // Boundary check: ensure thread processes valid element
    if (idx < n) {
        c[idx] = a[idx] + b[idx];
    }
}

int main() {
    int n = 1000000;  // Vector length
    size_t bytes = n * sizeof(float);

    // Host arrays (CPU memory)
    float *h_a = (float*)malloc(bytes);
    float *h_b = (float*)malloc(bytes);
    float *h_c = (float*)malloc(bytes);

    // Initialize input vectors
    for (int i = 0; i < n; i++) {
        h_a[i] = i;
        h_b[i] = i * 2;
    }

    // Device arrays (GPU memory)
    float *d_a, *d_b, *d_c;

    // Allocate device memory
    cudaMalloc(&d_a, bytes);
    cudaMalloc(&d_b, bytes);
    cudaMalloc(&d_c, bytes);

    // Copy input data from host to device
    cudaMemcpy(d_a, h_a, bytes, cudaMemcpyHostToDevice);
    cudaMemcpy(d_b, h_b, bytes, cudaMemcpyHostToDevice);

    // Configure kernel launch parameters
    int blockSize = 256;
    int gridSize = (n + blockSize - 1) / blockSize;

    // Launch kernel
    vectorAdd<<<gridSize, blockSize>>>(d_a, d_b, d_c, n);

    // Wait for kernel to complete
    cudaDeviceSynchronize();

    // Copy results from device to host
    cudaMemcpy(h_c, d_c, bytes, cudaMemcpyDeviceToHost);

    // Verify result (sample check)
    printf("c[0] = %f, c[1] = %f, c[%d] = %f\n", 
           h_c[0], h_c[1], n-1, h_c[n-1]);

    // Free device memory
    cudaFree(d_a);
    cudaFree(d_b);
    cudaFree(d_c);

    // Free host memory
    free(h_a);
    free(h_b);
    free(h_c);

    return 0;
}

// Vector Addition Kernel with Stride Pattern
// Handles vectors where n >> (gridDim × blockDim)

__global__ void vectorAddStrided(float *a, float *b, float *c, int n) {
    // Calculate starting index for this thread
    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    // Stride = total number of threads in grid
    int stride = blockDim.x * gridDim.x;

    // Process multiple elements per thread
    for (int i = idx; i < n; i += stride) {
        c[i] = a[i] + b[i];
    }
}

// Alternative: Grid-stride loop for flexibility
__global__ void vectorAddGridStride(float *a, float *b, float *c, long n) {
    for (long i = blockIdx.x * blockDim.x + threadIdx.x; 
         i < n; 
         i += blockDim.x * gridDim.x) {
        c[i] = a[i] + b[i];
    }
}

