// 2D Vector Addition (Matrix Addition)
// Adding two 2D matrices: C = A + B

#define ROWS 1024
#define COLS 1024

__global__ void matrixAdd(float *A, float *B, float *C, int rows, int cols) {
    // Calculate 2D thread position
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;

    // Convert to linear index
    int idx = row * cols + col;

    // Boundary check
    if (row < rows && col < cols) {
        C[idx] = A[idx] + B[idx];
    }
}

// Main function demonstrating 2D launch
void launch2DAddition() {
    float *d_A, *d_B, *d_C;
    size_t size = ROWS * COLS * sizeof(float);

    cudaMalloc(&d_A, size);
    cudaMalloc(&d_B, size);
    cudaMalloc(&d_C, size);

    // Configure 2D blocks and grid
    dim3 blockDim(16, 16);  // 16×16 = 256 threads per block
    dim3 gridDim((COLS + 15) / 16, (ROWS + 15) / 16);

    // Launch 2D kernel
    matrixAdd<<<gridDim, blockDim>>>(d_A, d_B, d_C, ROWS, COLS);

    cudaDeviceSynchronize();
    // ... copy results back and cleanup
}
